import{c as s,Q as e,j as n,m as p}from"./chunks/framework.CBiVa4O3.js";const g=JSON.parse('{"title":"CORS,Cookie 与跨域:前后端联调最常见的安全边界","description":"","frontmatter":{},"headers":[],"relativePath":"../cloudBasicsLearning/30-CORSCookie与跨域.md","filePath":"../cloudBasicsLearning/30-CORSCookie与跨域.md","lastUpdated":1779015580000}'),i={name:"../cloudBasicsLearning/30-CORSCookie与跨域.md"};function l(t,a,o,c,d,r){return e(),n("div",null,[...a[0]||(a[0]=[p(`<h1 id="cors-cookie-与跨域-前后端联调最常见的安全边界" tabindex="-1">CORS,Cookie 与跨域:前后端联调最常见的安全边界 <a class="header-anchor" href="#cors-cookie-与跨域-前后端联调最常见的安全边界" aria-label="Permalink to &quot;CORS,Cookie 与跨域:前后端联调最常见的安全边界&quot;">​</a></h1><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p><strong>CORS 是浏览器决定一个网页能不能读取另一个域名接口响应的规则;Cookie 是浏览器随请求自动携带的身份状态;跨域是前端页面和后端接口不在同一个 Origin 下访问时遇到的边界</strong>.</p><p>这三个词经常一起出现,因为独立开发最常见的部署方式就是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前端: https://app.example.com</span></span>
<span class="line"><span>后端: https://api.example.com</span></span>
<span class="line"><span>登录 Cookie: 发给 api.example.com 或 example.com</span></span></code></pre></div><p>本地开发时更明显:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前端: http://localhost:3000</span></span>
<span class="line"><span>后端: http://localhost:8080</span></span></code></pre></div><p>端口不同也算不同 Origin.浏览器会问:这个页面有没有资格读取那个接口的响应?这就是 CORS 常见报错的来源.</p><p>最容易误解的是:<strong>CORS 不是安全万能开关</strong>.它主要约束浏览器里的前端代码能不能读取跨域响应,不是后端接口的权限系统.攻击者可以不用浏览器,直接用 curl,脚本,Postman 调你的 API.你把 CORS 配得再严格,也不能替代登录校验,权限校验,CSRF 防护和服务端参数检查.</p><p>另一个常见误解是:<strong>允许跨域不等于允许带 Cookie</strong>.如果前端要跨域携带 Cookie,服务端,浏览器 Cookie 属性,前端请求参数都要同时配对,任何一处不对都会出现&quot;登录成功但下一次请求还是未登录&quot;.</p><h2 id="放在系统哪里" tabindex="-1">放在系统哪里 <a class="header-anchor" href="#放在系统哪里" aria-label="Permalink to &quot;放在系统哪里&quot;">​</a></h2><p>CORS 发生在浏览器和服务端之间,更准确地说,是浏览器在保护当前网页上下文:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>浏览器中的前端代码</span></span>
<span class="line"><span>  -&gt; 发起 fetch / XMLHttpRequest</span></span>
<span class="line"><span>  -&gt; 浏览器检查是否跨域</span></span>
<span class="line"><span>  -&gt; 必要时先发 OPTIONS 预检请求</span></span>
<span class="line"><span>  -&gt; CDN / 网关 / 反向代理</span></span>
<span class="line"><span>  -&gt; 后端 API</span></span>
<span class="line"><span>  -&gt; 浏览器根据 CORS 响应头决定前端能不能读取结果</span></span></code></pre></div><p>注意关键点:请求可能已经到了服务端,只是浏览器不把响应交给前端代码.很多人看到控制台报 CORS 错误,以为&quot;接口没有被调用&quot;,其实服务端日志里可能已经有请求了.</p><p>一次典型跨域登录链路是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户打开 https://app.example.com</span></span>
<span class="line"><span>  -&gt; 前端调用 https://api.example.com/login</span></span>
<span class="line"><span>  -&gt; 后端校验账号密码</span></span>
<span class="line"><span>  -&gt; 后端通过 Set-Cookie 写入 session</span></span>
<span class="line"><span>  -&gt; 浏览器保存 Cookie</span></span>
<span class="line"><span>  -&gt; 前端继续调用 https://api.example.com/me</span></span>
<span class="line"><span>  -&gt; 浏览器决定是否携带 Cookie</span></span>
<span class="line"><span>  -&gt; 后端根据 Cookie 识别用户</span></span></code></pre></div><p>这里至少涉及四类配置:</p><ul><li>API 响应头里的 <code>Access-Control-Allow-Origin</code>.</li><li>API 响应头里的 <code>Access-Control-Allow-Credentials</code>.</li><li>前端请求里的 <code>credentials: &quot;include&quot;</code> 或同类选项.</li><li>Cookie 本身的 <code>Domain</code>,<code>Path</code>,<code>SameSite</code>,<code>Secure</code>,<code>HttpOnly</code>.</li></ul><p>如果接口只是公开读数据,例如读取文章列表,通常不需要 Cookie,也不需要 <code>credentials</code>.如果接口涉及登录状态,用户资料,订单,后台操作,跨域 Cookie 就必须非常谨慎.</p><h2 id="常见套餐和使用限制" tabindex="-1">常见套餐和使用限制 <a class="header-anchor" href="#常见套餐和使用限制" aria-label="Permalink to &quot;常见套餐和使用限制&quot;">​</a></h2><p>CORS 本身通常不是单独收费产品,它常出现在这些地方:</p><ul><li>对象存储的跨域规则.</li><li>CDN 的响应头改写规则.</li><li>API Gateway 的 CORS 配置.</li><li>Serverless 函数或后端框架的中间件.</li><li>反向代理的 Header 配置.</li></ul><p>免费套餐常见限制不一定写着&quot;CORS 限制&quot;,而是藏在相邻能力里:</p><ul><li>响应头改写规则数量有限.</li><li>API Gateway 路由数量有限.</li><li>Serverless 对 OPTIONS 预检也计入请求数.</li><li>CDN 缓存了错误的 CORS Header,导致修复后仍然报错.</li><li>日志保留太短,排查不到预检请求和真实请求的差异.</li><li>自定义域名,HTTPS,Cookie <code>Secure</code> 需要更高套餐或额外配置.</li></ul><p>一个小团队常见坑:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前端部署到 https://app.example.com</span></span>
<span class="line"><span>后端部署到 https://api.example.com</span></span>
<span class="line"><span>开发时为了省事:</span></span>
<span class="line"><span>  Access-Control-Allow-Origin: *</span></span>
<span class="line"><span>  Access-Control-Allow-Credentials: true</span></span>
<span class="line"><span></span></span>
<span class="line"><span>结果浏览器直接拒绝:</span></span>
<span class="line"><span>  因为带 credentials 时不能使用通配符 *</span></span></code></pre></div><p>另一个坑是把 <code>SameSite=None</code> 写上了,但没有 <code>Secure</code>.现代浏览器通常要求跨站 Cookie 使用 <code>SameSite=None; Secure</code>,也就是必须走 HTTPS.本地 HTTP 调试,预览环境和正式环境经常因此表现不一致.</p><p>还有一个安全坑是动态反射 Origin:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请求 Origin 是什么,服务端就原样回什么</span></span></code></pre></div><p>如果没有白名单校验,这等于把任何站点都放进允许列表.对于带 Cookie 的接口,这会明显扩大风险.</p><h2 id="小团队建议" tabindex="-1">小团队建议 <a class="header-anchor" href="#小团队建议" aria-label="Permalink to &quot;小团队建议&quot;">​</a></h2><p>先把域名设计想清楚.最省心的方式是让前端和 API 处在同一个站点体系下:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://example.com        官网</span></span>
<span class="line"><span>https://app.example.com    应用前端</span></span>
<span class="line"><span>https://api.example.com    API</span></span></code></pre></div><p>如果可以,用同站点子域名,不要一会儿 <code>vercel.app</code>,一会儿 <code>workers.dev</code>,一会儿自定义域名.临时域名适合预览,不适合长期承载登录 Cookie.</p><p>最低限度建议:</p><ul><li>CORS 允许列表写具体 Origin,不要对带登录状态的接口使用 <code>*</code>.</li><li>不要把 CORS 当权限控制,服务端每个敏感接口都要校验用户身份和资源归属.</li><li>登录 Cookie 尽量设置 <code>HttpOnly</code> 和 <code>Secure</code>,减少被前端脚本读取和明文传输的风险.</li><li>明确 <code>SameSite</code> 策略.普通后台可以优先考虑 <code>Lax</code>;必须跨站嵌入或第三方回调时再评估 <code>None</code>.</li><li>把本地,预览,正式环境分开配置,不要把本地调试用的宽松规则带到生产.</li><li>记录 CORS 相关请求日志,尤其是 OPTIONS,Origin,状态码和被拒原因.</li></ul><p>什么时候需要更认真设计?</p><ul><li>你有浏览器登录态,并且前后端分域部署.</li><li>你要给第三方网站提供 API.</li><li>你有管理后台,支付,用户数据,上传接口.</li><li>你要把产品嵌入别人的网站,例如 iframe,小组件,插件.</li><li>你发现团队经常靠&quot;先把 CORS 放开&quot;来解决联调问题.</li></ul><p>排查 CORS 时不要只看浏览器控制台.正确顺序是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>确认前端 Origin</span></span>
<span class="line"><span>  -&gt; 确认是否需要 Cookie</span></span>
<span class="line"><span>  -&gt; 看 OPTIONS 预检是否成功</span></span>
<span class="line"><span>  -&gt; 看真实请求是否成功</span></span>
<span class="line"><span>  -&gt; 看响应头是否匹配</span></span>
<span class="line"><span>  -&gt; 看 Cookie 是否被浏览器保存和携带</span></span>
<span class="line"><span>  -&gt; 最后再看业务权限</span></span></code></pre></div><p>这能避免把登录失败,Cookie 丢失,权限 403,网关 502 全部误判成 CORS.</p><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p><strong>CORS 是浏览器跨域读取响应的边界,Cookie 是登录状态的自动携带机制;它们能减少前端跨域风险,但不能替代后端鉴权,权限校验和真实的业务安全设计</strong>.</p>`,43)])])}const u=s(i,[["render",l]]);export{g as __pageData,u as default};
